<?php
if (($_GET["key"] ?? "") !== "fsa-hub-deploy-2026") { die("Acesso negado."); }
header("Content-Type: text/plain; charset=utf-8");
echo "=== Instalando Pipeline + Operacional ===

";
$dir = rtrim(__DIR__, "/");
$files = array(
  "modules/pipeline/index.php" => "",
  "modules/pipeline/lead_form.php" => "",
  "modules/pipeline/lead_ver.php" => "",
  "modules/pipeline/api.php" => "",
  "modules/operacional/index.php" => "",
  "modules/operacional/caso_ver.php" => "",
  "modules/operacional/api.php" => "",
);
foreach ($files as $path => $content) {
  $full = $dir . "/" . $path;
  @mkdir(dirname($full), 0755, true);
  file_put_contents($full, base64_decode($content));
  @chmod($full, 0644);
  @chmod(dirname($full), 0755);
  echo "  OK: $path
";
}
echo "
=== PRONTO! ===
";
echo "Pipeline: /conecta/modules/pipeline/
";
echo "Operacional: /conecta/modules/operacional/
";
